  static String? actionKeyForCode(int actionCode) =>
      actionKeyByCode[actionCode];

  static int? actionCodeForKey(String actionKey) => actionCodeByKey[actionKey];

  static String? actionLabelForKey(String actionKey) =>
      actionLabelZhByKey[actionKey];

  static String? actionLabelForCode(int actionCode) {
    final key = actionKeyForCode(actionCode);
    if (key == null) return null;
    return actionLabelForKey(key);
  }

  static String? fieldLabelForKey(String fieldKey) =>
      fieldLabelZhByKey[fieldKey];

  static bool hasFieldLabel(String fieldKey) =>
      fieldLabelForKey(fieldKey) != null;

  static String? fieldValueForKey(
    String fieldKey,
    Map<String, String> values,
  ) {
    var template = fieldValueZhByKey[fieldKey];
    if (template == null) return null;
    for (final entry in values.entries) {
      template = template!.replaceAll('{${entry.key}}', entry.value);
    }
    return template;
  }

  static String? rejectReasonForKey(String reasonKey) =>
      rejectReasonZhByKey[reasonKey];

  static bool isHashOnlyAction(int actionCode) =>
      hashOnlyActionCodes.contains(actionCode);
